    def _send_email(self, to_email, subject, html_content):
        """Internal method to send email via Zoho SMTP or SendGrid"""
        try:
            # Try SendGrid first (if configured)
            if self.sendgrid_api_key:
                return self._send_via_sendgrid(to_email, subject, html_content)
            else:
                return self._send_via_zoho_smtp(to_email, subject, html_content)
        except Exception as e:
            print(f"Email sending failed: {str(e)}")
            return False

    def _send_via_sendgrid(self, to_email, subject, html_content):
        """Send via SendGrid API"""
        try:
            message = Mail(
                from_email=Email(self.from_email, self.from_name),
                to_emails=To(to_email),
                subject=subject,
                html_content=Content("text/html", html_content)
            )

            sg = SendGridAPIClient(self.sendgrid_api_key)
            response = sg.send(message)

            return response.status_code == 202
        except Exception as e:
            print(f"SendGrid error: {str(e)}")
            return False

    def _send_via_zoho_smtp(self, to_email, subject, html_content):
        """Send via Zoho SMTP"""
        import smtplib
        from email.mime.text import MIMEText
        from email.mime.multipart import MIMEMultipart

        try:
            msg = MIMEMultipart('alternative')
            msg['Subject'] = subject
            msg['From'] = f"{self.from_name} <{self.from_email}>"
            msg['To'] = to_email

            html_part = MIMEText(html_content, 'html')
            msg.attach(html_part)

            with smtplib.SMTP(self.smtp_host, self.smtp_port) as server:
                server.starttls()
                server.login(self.smtp_username, self.smtp_password)
                server.send_message(msg)

            return True
        except Exception as e:
            print(f"Zoho SMTP error: {str(e)}")
            return False

    def verify_code(self, email, code):
        """Verify the email verification code"""
        cache_key = f'email_verification_{email}'
        stored_code = cache.get(cache_key)

        if stored_code and stored_code == code:
            cache.delete(cache_key)  # Remove after successful verification
            return True
        return False

    def verify_reset_token(self, email, token):
        """Verify the password reset token"""
        cache_key = f'password_reset_{email}'
        stored_token = cache.get(cache_key)

        if stored_token and stored_token == token:
            return True
        return False

    def invalidate_reset_token(self, email):
        """Invalidate reset token after password change"""
        cache_key = f'password_reset_{email}'
        cache.delete(cache_key)


